var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤엑, 힉, 히엑……! 주, 주주, 죽겠어요……!","JPN":"ふえっ、ひいっ、ひええっ……！　し、しし、死にます……！","ENG":"*Huff* *Huff* Pant* *Pant*... I-I can't...! I'm dying...!","TWN":"哈哈，呼，呼哈……！我，我，我快死了……！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘, 벌써 페이스가 흐트러지면 어떡해요.","JPN":"ノエルさん、もうペースが乱れたらどうするんですか？","ENG":"You can't fall behind already, Noelle.","TWN":"洛艾兒，要穩住呼吸。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아직 2킬로미터는 더 뛰어야 돼요. 꿈을 이루게 도와 준다면서요.","JPN":"まだ2キロは走らないと。夢を叶えられるように手伝ってくれるって言ったでしょう？","ENG":"You need to run two kilometers more, at the very least. Didn't you say you'd help me make my dreams come true?","TWN":"還得再跑二公里呢。你不是說要幫我實現夢想嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 잠깐 쉬고 다시 뛰자. 이러다 송장 치우겠다.","JPN":"おい、ちょっと休んでから走らないか。これじゃあ、後で死体を運ぶことになりかねない。","ENG":"Yo, we should probably take a break before we have to put her in a body bag.","TWN":"小鬼，讓她休息一下吧，再跑下去就要替她收屍了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우으, 저에겐 너무 힘든 도전이었나 봐요….","JPN":"うう、私にはとても無理な挑戦だったようです……","ENG":"Ouugh... Maybe this was too big a challenge for me...","TWN":"嗚嗚，這個挑戰，對我來說好像太難了……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"유리한 고지를 선점하는 것도 결국 체력 싸움인데….","JPN":"有利な場所を先取りするのも結局は体力次第なのに……","ENG":"Taking and maintaining the high ground is eventually a matter of stamina...","TWN":"說到底搶佔具有優勢的高地也是體力之戰……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그렇게 기초 체력도 부족하면서 건틀렛에 나가려고 했어요?","JPN":"こんなに基礎体力もないのに、ガントレットに出ようとしたのですか？","ENG":"Why did you decide to compete in the first place, especially when you're in such bad shape?","TWN":"你的體能那麼差，還想參加聖鎧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"별 수 있냐. 원래부터 엔트리에 이름만 빌려 줄 예정이었잖아.","JPN":"仕方ないだろ。元々エントリーに名前だけ貸してもらう予定だったんだし。","ENG":"What can we do? Besides, she was just an extra name on our entry list.","TWN":"有什麼辦法？她本來就是用來湊人數的嘛。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그래도 드론보다는 쓸모가 있어야죠. 카운터 한 명에 포인트가 얼만데.","JPN":"それでも、ドローンよりは役に立たないと。カウンター一人に、何ポイントかかってると思っているの？","ENG":"Shouldn't she be better than a drone, at least? It takes a fortune to register a Counter.","TWN":"那她也應該比無人機更有用吧，制裁者消耗的點數比較多欸。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘의 역할은 단독으로 움직이면서 유리한 고지를 선점한 뒤 적을 견제하는 거예요.","JPN":"ノエルさんの役割は単独で動いて有利な場所を先に占有した後、敵を牽制することです。","ENG":"Your job is to act alone, take the high ground, and mark the enemies.","TWN":"洛艾兒你負責單獨行動，搶佔有優勢的高地後牽制敵人。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"마음 단단히 먹어요. 실전에서도 이렇게 낙오되면 그냥 버릴 테니까요.","JPN":"気を引き締めてください。実戦でもこんな風に脱落したら、そのまま捨てちゃいますから。","ENG":"Get yourself together. If you can't keep up with us in the actual competition, we're just going to leave you behind.","TWN":"你做好心理準備。如果在實戰中也這樣脫隊，我們是會棄你不顧的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"며, 명심하겠습니다!","JPN":"りょ、了解いたしました！","ENG":"Y-yes, ma'am!","TWN":"我，我記住了！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"꽤 강도 높은 트레이닝을 하는군.","JPN":"結構ハードなトレーニングをするんだな。","ENG":"The training seems to be quite intense.","TWN":"訓練的強度很強呢。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저러다 키가 안 큰다고 하니까 자기는 그게 좋대요. 피탄 면적은 작을수록 좋다나.","JPN":"そうしてると背が伸びないよって言っても、自分はそれがいいんですって。被弾面積は狭いほどいいとか？","ENG":"I told her she's not going to get any taller like that, and she said she prefers it. Says she doesn't want to be a bigger target or something.","TWN":"我跟她說訓練過度會長不高，結果她說這樣才好，因為不容易被子彈打到。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"사실 펠리세트가 독해서 그렇지, 제대로 지원 못 받는 팀들은 대부분 저런 식이에요.","JPN":"正直フェリセットは根性があるから大丈夫なだけで、ちゃんとしたサポートを受けられないチームはほとんどがあんな感じなんです。","ENG":"Well, Félicette is pretty tough, but most teams who don't get proper funding are like that.","TWN":"那孩子也是有苦衷的，其實得不到援助的隊伍大部分都是這樣的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"훈련 시설 대여비는 시즌 중에 엄청 뛰고, 연습용 탄환도 한 발 한 발이 지출이니까요.","JPN":"シーズン中の訓練施設の賃貸料は跳ね上がるし、練習用の弾丸も一発一発が全部お金ですから。","ENG":"The rent for training centers skyrockets during the competition season, not to mention the price of ammo used for practice.","TWN":"訓練場地的租金在賽季期間會猛漲，每一發練習用彈藥也都是錢。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};